using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool PurchaseItem(int itemPrice)
    {
        if (currency >= itemPrice)
        {
            currency -= itemPrice;
            return true;
        }
        return false;
    }
}

public class DamageCalculator : MonoBehaviour
{
    public int baseDamage = 10;

    public int CalculateDamage(int multiplier)
    {
        return baseDamage * multiplier;
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void BuyItem(int itemPrice)
    {
        if (playerStats.PurchaseItem(itemPrice))
        {
            // Item purchased logic here
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public DamageCalculator damageCalculator;

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Space)) // Simulate taking damage
        {
            int damage = damageCalculator.CalculateDamage(1);
            playerStats.TakeDamage(damage);
        }

        // Simulate currency addition
        if (Input.GetKeyDown(KeyCode.C))
        {
            playerStats.AddCurrency(20);
        }

